const n=JSON.parse('{"key":"v-5bf66ca1","path":"/MyNotes/%E9%9D%A2%E8%AF%95-MySQL.html","title":"面试-MySQL","lang":"zh-CN","frontmatter":{"icon":"/icon/streamline-stickies-color--face-id-1.svg","date":"2026-02-28T00:00:00.000Z","category":["面试"],"footer":"面试是检验，笔记是沉淀，成长是最终答案。","tag":["面试-MySQL"],"description":"面试-MySQL 日常工作中怎么优化SQL 问：日常工作中怎么优化SQL 答：加索引减少返回的数据列避免走全表扫描、避免子查询分库分表 # 创建索引语句 CREATE INDEX 索引名 ON 表名(列名1, 列名2...); # 创建表的时候加索引 CREATE TABLE 表名 ( 列名1 数据类型, 列名2 数据类型, 列名3 数据类型, -- 唯一索引 UNIQUE KEY 索引名 (列名2), -- 普通索引(KEY和INDEX 等价，KEY更简洁) KEY 索引名 (列名2) );","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/MyNotes/%E9%9D%A2%E8%AF%95-MySQL.html"}],["meta",{"property":"og:site_name","content":"TenSoFlowBlog"}],["meta",{"property":"og:title","content":"面试-MySQL"}],["meta",{"property":"og:description","content":"面试-MySQL 日常工作中怎么优化SQL 问：日常工作中怎么优化SQL 答：加索引减少返回的数据列避免走全表扫描、避免子查询分库分表 # 创建索引语句 CREATE INDEX 索引名 ON 表名(列名1, 列名2...); # 创建表的时候加索引 CREATE TABLE 表名 ( 列名1 数据类型, 列名2 数据类型, 列名3 数据类型, -- 唯一索引 UNIQUE KEY 索引名 (列名2), -- 普通索引(KEY和INDEX 等价，KEY更简洁) KEY 索引名 (列名2) );"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-03-04T12:35:49.000Z"}],["meta",{"property":"article:author","content":"TenSoFlow"}],["meta",{"property":"article:tag","content":"面试-MySQL"}],["meta",{"property":"article:published_time","content":"2026-02-28T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2026-03-04T12:35:49.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"面试-MySQL\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2026-02-28T00:00:00.000Z\\",\\"dateModified\\":\\"2026-03-04T12:35:49.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"TenSoFlow\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":3,"title":"日常工作中怎么优化SQL","slug":"日常工作中怎么优化sql","link":"#日常工作中怎么优化sql","children":[]},{"level":3,"title":"MySQL为什么使用B+Tree作为索引结构","slug":"mysql为什么使用b-tree作为索引结构","link":"#mysql为什么使用b-tree作为索引结构","children":[]},{"level":3,"title":"数据库连接池有什么用","slug":"数据库连接池有什么用","link":"#数据库连接池有什么用","children":[]},{"level":3,"title":"数据库连接池有哪些关键参数","slug":"数据库连接池有哪些关键参数","link":"#数据库连接池有哪些关键参数","children":[]}],"git":{"createdTime":1772456290000,"updatedTime":1772627749000,"contributors":[{"name":"曹卫民","email":"1413468037@qq.com","commits":2}]},"readingTime":{"minutes":2.84,"words":851},"filePathRelative":"MyNotes/面试-MySQL.md","localizedDate":"2026年2月28日","excerpt":"<h1> 面试-MySQL</h1>\\n<h3> 日常工作中怎么优化SQL</h3>\\n<details class=\\"hint-container details\\"><summary><b style=\\"color:#bf3e73\\">问：日常工作中怎么优化SQL</b></summary>\\n<p><b style=\\"color:#f19977\\">答：加索引<br>减少返回的数据列<br>避免走全表扫描、避免子查询<br>分库分表</b></p>\\n</details>\\n<div class=\\"language-sql line-numbers-mode\\" data-ext=\\"sql\\"><pre class=\\"language-sql\\"><code><span class=\\"token comment\\"># 创建索引语句</span>\\n<span class=\\"token keyword\\">CREATE</span> <span class=\\"token keyword\\">INDEX</span> 索引名 <span class=\\"token keyword\\">ON</span> 表名<span class=\\"token punctuation\\">(</span>列名<span class=\\"token number\\">1</span><span class=\\"token punctuation\\">,</span> 列名<span class=\\"token number\\">2.</span><span class=\\"token punctuation\\">.</span><span class=\\"token punctuation\\">.</span><span class=\\"token punctuation\\">)</span><span class=\\"token punctuation\\">;</span>\\n\\n<span class=\\"token comment\\"># 创建表的时候加索引</span>\\n<span class=\\"token keyword\\">CREATE</span> <span class=\\"token keyword\\">TABLE</span> 表名 <span class=\\"token punctuation\\">(</span>\\n    列名<span class=\\"token number\\">1</span> 数据类型<span class=\\"token punctuation\\">,</span>\\n    列名<span class=\\"token number\\">2</span> 数据类型<span class=\\"token punctuation\\">,</span>\\n    列名<span class=\\"token number\\">3</span> 数据类型<span class=\\"token punctuation\\">,</span>\\n    <span class=\\"token comment\\">-- 唯一索引</span>\\n    <span class=\\"token keyword\\">UNIQUE</span> <span class=\\"token keyword\\">KEY</span> 索引名 <span class=\\"token punctuation\\">(</span>列名<span class=\\"token number\\">2</span><span class=\\"token punctuation\\">)</span><span class=\\"token punctuation\\">,</span>\\n    <span class=\\"token comment\\">-- 普通索引(KEY和INDEX 等价，KEY更简洁)</span>\\n    <span class=\\"token keyword\\">KEY</span> 索引名 <span class=\\"token punctuation\\">(</span>列名<span class=\\"token number\\">2</span><span class=\\"token punctuation\\">)</span>\\n<span class=\\"token punctuation\\">)</span><span class=\\"token punctuation\\">;</span>\\n</code></pre><div class=\\"line-numbers\\" aria-hidden=\\"true\\"><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div></div></div>","copyright":{"author":"TenSoFlow","license":"MIT"},"autoDesc":true}');export{n as data};
